SELECT count(*) FROM info_type, movie_info, title, movie_companies, company_type, company_name, cast_info, movie_keyword WHERE movie_info.info_type_id = info_type.id AND movie_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id;